}
.how-bar-sub{
  font-size:13px;
  color:var(--muted);
  line-height:1.45;
}
.how-bar-divider{
  width:1px;
  height:60px;
  background:var(--line2);
  margin:0 20px;
}

/* ── PROCESS STEPS ───────────────────────────────── */
.process-section{
  max-width:1520px;
  margin:0 auto;
  padding:80px 68px 100px;
}
.process-steps{
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:0;
  position:relative;
  max-width:1000px;
  margin:0 auto;
}
.process-steps::before{
  content:'';
  position:absolute;
  top:27px;
  left:calc(12.5% + 14px);
  right:calc(12.5% + 14px);
  height:1px;
  background:rgba(11,114,255,0.30);
  z-index:0;
}
.process-step{
  text-align:center;
  padding:0 20px;
  position:relative;
  z-index:1;
}
.step-circle{
  width:56px;height:56px;
  border-radius:50%;
  background:var(--navy2);
  border:1px solid rgba(11,114,255,0.35);
  display:flex;align-items:center;justify-content:center;
  margin:0 auto 24px;
}
.step-circle svg{width:22px;height:22px;color:rgba(178,191,207,0.85)}
.step-num{
  font-size:10px;
  font-weight:700;
  letter-spacing:.12em;
  text-transform:uppercase;
  color:var(--blue);
  margin-bottom:8px;
}
.step-title{
  font-size:17px;
  font-weight:700;
  letter-spacing:-.02em;
  margin-bottom:10px;
}
.step-desc{
  font-size:13px;
  color:var(--muted);
  line-height:1.60;
}

/* ── CTA BANNER ──────────────────────────────────── */
.cta-section{
  background:var(--navy2);
  border-top:1px solid var(--line);
}
.cta-inner{
  max-width:1520px;
  margin:0 auto;
  padding:0 68px;
}
.cta-box{
  background:
    radial-gradient(ellipse 70% 100% at 50% -10%, rgba(11,114,255,0.18) 0%, transparent 65%),
    rgba(255,255,255,0.025);
  border:1px solid rgba(11,114,255,0.25);
  border-radius:16px;
  padding:72px 80px;
  text-align:center;
  margin:80px 0 100px;
}
.cta-box h2{
  font-size:clamp(28px,3.2vw,46px);
  font-weight:700;
  letter-spacing:-.04em;
  margin-bottom:14px;
}
.cta-box p{
  font-size:16px;
  color:var(--muted);
  margin-bottom:40px;
}
.cta-row{
  display:flex;
  align-items:center;
  justify-content:center;
  gap:20px;
  flex-wrap:wrap;
}
.cta-note{
  display:flex;
  align-items:center;
  gap:7px;
  font-size:13px;
  color:rgba(255,255,255,0.40);
}
.cta-note svg{width:13px;height:13px;flex-shrink:0}

/* ── FOOTER ──────────────────────────────────────── */
footer{
  border-top:1px solid var(--line);
  padding:32px 68px;
  display:flex;
  align-items:center;
  justify-content:space-between;
}
.footer-logo{
  font-size:13px;
  font-weight:700;
  letter-spacing:.18em;
  text-transform:uppercase;
  color:rgba(255,255,255,0.35);
}
.footer-copy{font-size:12px;color:rgba(255,255,255,0.25)}

/* ── FADE-IN ─────────────────────────────────────── */
.fade{opacity:0;transform:translateY(24px);transition:opacity .6s ease, transform .6s ease}
.fade.in{opacity:1;transform:translateY(0)}
.d1{transition-delay:.10s}.d2{transition-delay:.20s}.d3{transition-delay:.30s}.d4{transition-delay:.40s}

/* ══════════════════════════════════════════════════
   RESPONSIVE — 1100px
══════════════════════════════════════════════════ */
@media(max-width:1100px){
  .header{padding:0 36px;height:80px;}
  .main-hero-inner{padding:72px 36px 80px;gap:40px;}
  .main-h1{font-size:clamp(36px,5vw,56px);}
  .hero{padding:64px 36px 80px;}
  .services-detail,.why-inner,.how-cards,.process-section,.cta-section{
    padding-left:36px;padding-right:36px;
  }
  .industry-inner{padding:26px 36px 32px;}
}

/* ══════════════════════════════════════════════════
   RESPONSIVE — 860px (tablet → single column)
══════════════════════════════════════════════════ */
@media(max-width:860px){
  /* Header */
  .header{padding:0 24px;height:68px;}
  .nav{display:none;}

  /* Mobile drawer */
  .nav.open{
    display:flex;
    flex-direction:column;
    align-items:flex-start;
    position:fixed;
    top:68px;left:0;right:0;bottom:0;
    z-index:200;
    background:#040c1b;
    border-top:1px solid var(--line);
    padding:40px 28px 44px;
    gap:4px;
  }
  .nav.open a{
    font-size:20px;font-weight:500;
    letter-spacing:-.02em;
    padding:12px 4px;
    width:100%;
    color:rgba(255,255,255,0.80);
    border-bottom:1px solid rgba(255,255,255,0.06);
    border-radius:0;
  }
  .nav.open .btn-nav{
    margin-top:22px;font-size:15px;
    padding:16px 28px;width:100%;
    text-align:center;justify-content:center;
    border-radius:10px;border-bottom:none;
  }

  /* Burger */
  .burger{
    display:flex;
    flex-direction:column;
    gap:5px;
    background:none;
    border:none;
    cursor:pointer;
    padding:6px;
    border-radius:6px;
  }
  .burger span{
    display:block;width:22px;height:1.5px;
    background:rgba(255,255,255,0.75);
    border-radius:2px;transform-origin:center;transition:.22s;
  }

  /* Main hero — reordenar elementos en mobile */
  .main-hero-inner{
    display:flex !important;
    flex-direction:column !important;
    padding:52px 24px 56px;
    gap:0;
  }
  /* hero-left se convierte en contenedor transparente para hijos */
  .hero-left{
    display:contents;
  }
  /* Orden: eyebrow+h1+paras primero, luego imagen, luego tagline+boton */
  .hero-left .eyebrow{ order:1; margin-bottom:20px; }
  .hero-left .main-h1{ order:2; }
  .hero-left .main-paras{ order:3; margin-bottom:24px; }
  .hero-right{ order:4; min-height:auto; margin-bottom:28px; }
  .hero-left .main-tagline{ order:5; font-size:17px; margin-bottom:20px; }
  .hero-left .btn-primary{ order:6; }
  .dash-wrap{max-width:100%;}

  /* Hero section (2nd section) — reordenar widget antes del botón */
  .hero{
    display:flex !important;
    flex-direction:column !important;
    padding:52px 24px 60px;
    gap:0;
  }
  /* hero-content se convierte en contenedor transparente */
  .hero-content{
    display:contents;
  }
  .hero-content h1{ order:1; font-size:clamp(32px,9vw,48px); margin-bottom:18px; }
  .hero-content .hero-sub{ order:2; margin-bottom:16px; }
  .hero-content .hero-tagline{ order:3; margin-bottom:24px; }
  .tab-widget{ order:4; margin-bottom:28px; }
  .hero-content .btn-primary{ order:5; }

  /* Services detail */
  .services-detail{padding:56px 24px 72px;}
  .service-block{
    grid-template-columns:1fr !important;
    gap:0;
  }
  .service-block.reverse{direction:ltr;}

  /* Reduce icon/visual area height on mobile */
  .service-visual{
    min-height:160px !important;
    padding:24px 20px !important;
  }
  .svc-icon-img img,
  .svc-icon-img svg{
    width:120px !important;
    height:120px !important;
  }
  .svc-icon-ring{
    width:80px !important;
    height:80px !important;
  }
  .svc-icon-ring svg{
    width:34px !important;
    height:34px !important;
  }

  /* Service info padding on mobile */
  .service-info{
    padding:28px 20px !important;
  }

  /* Feature grid */
  .feature-grid{grid-template-columns:1fr !important;}

  /* Why section — stack cards, armonizar tipografía */
  .why-inner{
    padding:56px 24px 72px;
  }
  .why-grid{
    grid-template-columns:1fr !important;
    display:flex !important;
    flex-direction:column !important;
    gap:20px !important;
  }
  .why-left{
    order:1;
    padding:32px 24px !important;
  }
  .why-right{
    order:2;
    padding:32px 24px !important;
  }
  .why-left h3{
    font-size:21px !important;
    font-weight:700 !important;
    letter-spacing:-0.025em !important;
    line-height:1.18 !important;
    margin-bottom:14px !important;
  }
  .why-left p{
    font-size:14px !important;
    line-height:1.70 !important;
    margin-bottom:12px !important;
  }
  .why-tagline{
    font-size:13px !important;
    padding-top:16px !important;
    margin-top:6px !important;
  }
  .crown{
    font-size:22px !important;
    margin-bottom:12px !important;
  }
  .why-right h3{
    font-size:16px !important;
    font-weight:700 !important;
    letter-spacing:-0.015em !important;
    margin-bottom:18px !important;
  }
  .why-list li{
    font-size:14px !important;
    line-height:1.50 !important;
    padding:11px 0 !important;
    gap:12px !important;
  }

  /* How cards */
  .how-cards{
    grid-template-columns:1fr !important;
    padding:0 24px;
    gap:16px;
  }
  .how-bar{
    grid-template-columns:1fr 1fr !important;
    gap:20px;
    padding:28px 24px;
  }
  .how-bar-divider{display:none;}

  /* Process steps */
  .process-section{padding:56px 24px 72px;}
  .process-steps{
    grid-template-columns:1fr !important;
    gap:20px;
  }
  .process-steps::before{display:none;}

  /* Industry strip */
  .industry-inner{padding:22px 24px 28px;}
  .industry-grid{
    grid-template-columns:repeat(3,1fr) !important;
    gap:0;
  }
  .industry-item{border-right:none;border-bottom:1px solid var(--line);padding:14px 10px;}
  .industry-item:nth-child(3),.industry-item:last-child{border-bottom:none;}

  /* Tab widget */
  .tab-header{flex-wrap:wrap;}

  /* CTA */
  .cta-section{padding:40px 16px 60px;}
  .cta-box{padding:52px 20px 56px;}
  .cta-row{flex-direction:column;align-items:stretch;gap:16px;}
  .cta-row .btn-primary{
    width:100%;
    justify-content:center;
    padding:18px 32px;
    font-size:13px;
    white-space:normal;
    text-align:center;
    line-height:1.4;
  }

  /* Footer */
  footer{
    flex-direction:column;gap:16px;
    text-align:center;
    padding:28px 24px;
  }

  /* Buttons */
  .btn-primary{width:100%;justify-content:center;}
}

